import json

# Test the balanced JSON parser algorithm directly without f-string issues

def _first_balanced_json(text: str) -> str | None:
    """
    Return the first balanced {...} or [...] span, respecting string literals.
    """
    start = None
    for i, ch in enumerate(text):
        if ch in "{[":
            start = i
            break
    if start is None:
        return None
    open_ch = text[start]
    close_ch = "}" if open_ch == "{" else "]"
    depth = 0
    in_str = False
    escaped = False
    for i in range(start, len(text)):
        ch = text[i]
        if in_str:
            if escaped:
                escaped = False
            elif ch == "\\":
                escaped = True
            elif ch == '"':
                in_str = False
            continue
        if ch == '"':
            in_str = True
        elif ch == open_ch:
            depth += 1
        elif ch == close_ch:
            depth -= 1
            if depth == 0:
                return text[start:i + 1]
    return None

# Test: escaped quote followed by close brace
# In JSON string literals, \" represents a quote character
# The actual string: {"s": "\""}  should parse as {"s": "\""}
