import json
from typing import Optional

def _extract_json(text: str) -> dict:
    """Recover a JSON value from a model reply that may include fences/prose."""
    candidate = text.strip()
    # Strip a ```json ... ``` fence if present.
    if candidate.startswith("```"):
        inner = candidate[3:]
        if inner[:4].lower() == "json":
            inner = inner[4:]
        candidate = inner.rsplit("```", 1)[0].strip()
    try:
        return json.loads(candidate)
    except json.JSONDecodeError:
        pass

    # The balanced-brace extractor
    def _first_balanced_json(text: str) -> Optional[str]:
        start = None
        for i, ch in enumerate(text):
            if ch in "{[":
                start = i
                break
        if start is None:
            return None
        open_ch = text[start]
        close_ch = "}" if open_ch == "{" else "]"
        depth = 0
        in_str = False
        escaped = False
        for i in range(start, len(text)):
            ch = text[i]
            if in_str:
                if escaped:
                    escaped = False
                elif ch == "\\":
                    escaped = True
                elif ch == '"':
                    in_str = False
                continue
            if ch == '"':
                in_str = True
            elif ch == open_ch:
                depth += 1
            elif ch == close_ch:
                depth -= 1
                if depth == 0:
                    return text[start:i + 1]
        return None

    span = _first_balanced_json(candidate)
    if span is not None:
        try:
            return json.loads(span)
        except json.JSONDecodeError as exc:
            raise ValueError(f"Reply was not valid JSON: {text[:200]!r}") from exc
    raise ValueError(f"No JSON value found in reply: {text[:200]!r}")

# Test cases
tests = [
    # Normal case
    ('{"type": "decision", "value": "approved"}', {"type": "decision", "value": "approved"}),

    # With markdown fence
    ('```json\n{"type": "decision"}\n```', {"type": "decision"}),

    # With prose before and after
    ('The decision is: {"type": "approved"} which is final', {"type": "approved"}),

    # List instead of object
    ('[1, 2, 3]', [1, 2, 3]),

    # Complex nested structure
    ('{"decisions": [{"id": 1, "text": "yes"}]}', {"decisions": [{"id": 1, "text": "yes"}]}),

    # With quotes in string values
    ('{"quote": "He said \\"hello\\""}', {"quote": 'He said "hello"'}),
]

for i, (input_text, expected) in enumerate(tests):
    try:
        result = _extract_json(input_text)
        match = result == expected
        print(f"Test {i+1}: {'PASS' if match else 'FAIL'}")
        if not match:
            print(f"  Input: {input_text}")
            print(f"  Expected: {expected}")
            print(f"  Got: {result}")
    except Exception as e:
        print(f"Test {i+1}: ERROR - {e}")

